namespace sv_496ceae5f0bc40219888b1763978618f.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTime EstimatedDelivery,
    List<StatusUpdate> StatusUpdates);

public record StatusUpdate(DateTime Timestamp, string Description);

using sv_496ceae5f0bc40219888b1763978618f.Client.Services;

namespace sv_496ceae5f0bc40219888b1763978618f.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            "TRK-001",
            "In Transit",
            "Chicago, IL",
            new DateTime(2026, 5, 28),
            new List<StatusUpdate>
            {
                new(new DateTime(2026, 5, 20, 9, 0, 0), "Package picked up from sender"),
                new(new DateTime(2026, 5, 21, 14, 30, 0), "Arrived at sorting facility - Chicago, IL"),
                new(new DateTime(2026, 5, 22, 8, 15, 0), "In transit to destination")
            }),
        ["TRK-002"] = new ShipmentDetails(
            "TRK-002",
            "Delivered",
            "Austin, TX",
            new DateTime(2026, 5, 22),
            new List<StatusUpdate>
            {
                new(new DateTime(2026, 5, 18, 10, 0, 0), "Package picked up from sender"),
                new(new DateTime(2026, 5, 19, 16, 45, 0), "Arrived at sorting facility - Dallas, TX"),
                new(new DateTime(2026, 5, 20, 11, 0, 0), "Out for delivery"),
                new(new DateTime(2026, 5, 20, 15, 30, 0), "Delivered - Left at front door")
            }),
        ["TRK-003"] = new ShipmentDetails(
            "TRK-003",
            "Processing",
            "Seattle, WA",
            new DateTime(2026, 5, 30),
            new List<StatusUpdate>
            {
                new(new DateTime(2026, 5, 23, 12, 0, 0), "Order confirmed, awaiting pickup")
            })
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' not found.");
    }
}

using Microsoft.AspNetCore.Mvc;
using sv_496ceae5f0bc40219888b1763978618f.Client.Services;

namespace sv_496ceae5f0bc40219888b1763978618f.Controllers;

[ApiController]
[Route("api/shipments")]
public class ShipmentController : ControllerBase
{
    private readonly IShipmentService _shipmentService;

    public ShipmentController(IShipmentService shipmentService)
    {
        _shipmentService = shipmentService;
    }

    [HttpGet("{trackingNumber}")]
    public async Task<ActionResult<ShipmentDetails>> Get(string trackingNumber, CancellationToken ct)
    {
        try
        {
            var shipment = await _shipmentService.GetShipmentAsync(trackingNumber, ct);
            return Ok(shipment);
        }
        catch (KeyNotFoundException)
        {
            return NotFound();
        }
    }
}

using System.Net;
using System.Net.Http.Json;

namespace sv_496ceae5f0bc40219888b1763978618f.Client.Services;

public class ShipmentHttpClient : IShipmentService
{
    private readonly HttpClient _httpClient;

    public ShipmentHttpClient(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await _httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' not found.");
        }

        response.EnsureSuccessStatusCode();

        var shipment = await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct)
            ?? throw new InvalidOperationException("Received null response from server.");

        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_496ceae5f0bc40219888b1763978618f.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Track Shipment - @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("MMMM d, yyyy")</dd>
        </dl>

        <h3>Status Updates</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.StatusUpdates)
            {
                <li>
                    <time datetime="@update.Timestamp.ToString("o")">@update.Timestamp.ToString("g")</time>
                    &mdash; @update.Description
                </li>
            }
        </ul>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any previous in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _shipment = null;
        _errorMessage = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed; do nothing
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || !ct.IsCancellationRequested)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (KeyNotFoundException ex)
        {
            Logger.LogWarning(ex, "Shipment not found: {TrackingNumber}", TrackingNumber);
            _errorMessage = $"Shipment '{TrackingNumber}' was not found.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryLoad()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

