using sv_496ceae5f0bc40219888b1763978618f.Client.Services;

namespace sv_496ceae5f0bc40219888b1763978618f.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            "TRK-001",
            "In Transit",
            "Chicago, IL",
            new DateTime(2026, 5, 28),
            new List<StatusUpdate>
            {
                new(new DateTime(2026, 5, 20, 9, 0, 0), "Package picked up from sender"),
                new(new DateTime(2026, 5, 21, 14, 30, 0), "Arrived at sorting facility - Chicago, IL"),
                new(new DateTime(2026, 5, 22, 8, 15, 0), "In transit to destination")
            }),
        ["TRK-002"] = new ShipmentDetails(
            "TRK-002",
            "Delivered",
            "Austin, TX",
            new DateTime(2026, 5, 22),
            new List<StatusUpdate>
            {
                new(new DateTime(2026, 5, 18, 10, 0, 0), "Package picked up from sender"),
                new(new DateTime(2026, 5, 19, 16, 45, 0), "Arrived at sorting facility - Dallas, TX"),
                new(new DateTime(2026, 5, 20, 11, 0, 0), "Out for delivery"),
                new(new DateTime(2026, 5, 20, 15, 30, 0), "Delivered - Left at front door")
            }),
        ["TRK-003"] = new ShipmentDetails(
            "TRK-003",
            "Processing",
            "Seattle, WA",
            new DateTime(2026, 5, 30),
            new List<StatusUpdate>
            {
                new(new DateTime(2026, 5, 23, 12, 0, 0), "Order confirmed, awaiting pickup")
            })
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' not found.");
    }
}

